  "inlineSchema": "// DevComply Database Schema\n// Engine: PostgreSQL\n// Notes: Uses UUIDs for all primary keys to prevent enumeration attacks and ensure distributed scalability.\n\ngenerator client {\n  provider        = \"prisma-client-js\"\n  previewFeatures = [\"postgresqlExtensions\"]\n}\n\ndatasource db {\n  provider   = \"postgresql\"\n  url        = env(\"DATABASE_URL\")\n  directUrl  = env(\"DIRECT_URL\")\n  extensions = [pgvector(map: \"vector\")]\n}\n\n// Enumerations\nenum Role {\n  ADMIN\n  MEMBER\n}\n\nenum ScanStatus {\n  PENDING\n  ANALYZING\n  COMPLETED\n  FAILED\n}\n\nenum FindingSeverity {\n  CRITICAL\n  HIGH\n  MEDIUM\n  LOW\n  INFO\n}\n\nenum FindingStatus {\n  OPEN\n  IGNORED\n  RESOLVED\n}\n\n// Core Models\nmodel User {\n  id                   String    @id @default(uuid()) @db.Uuid\n  email                String    @unique\n  githubId             Int       @unique\n  name                 String?\n  avatarUrl            String?\n  encryptedGithubToken String?\n  createdAt            DateTime  @default(now())\n  updatedAt            DateTime  @updatedAt\n  deletedAt            DateTime?\n\n  memberships UserOrganization[]\n\n  @@map(\"users\")\n}\n\nmodel Organization {\n  id                   String    @id @default(uuid()) @db.Uuid\n  name                 String\n  githubOrgId          Int       @unique\n  githubOrgLogin       String\n  encryptedGithubToken String // AES-256-GCM encrypted token\n  createdAt            DateTime  @default(now())\n  updatedAt            DateTime  @updatedAt\n  deletedAt            DateTime?\n\n  memberships  UserOrganization[]\n  repositories Repository[]\n\n  @@map(\"organizations\")\n}\n\nmodel UserOrganization {\n  userId         String   @db.Uuid\n  organizationId String   @db.Uuid\n  role           Role     @default(MEMBER)\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  user         User         @relation(fields: [userId], references: [id], onDelete: Cascade)\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n\n  @@id([userId, organizationId]) // Composite Primary Key\n  @@index([organizationId])\n  @@map(\"user_organizations\")\n}\n\nmodel Repository {\n  id             String    @id @default(uuid()) @db.Uuid\n  organizationId String    @db.Uuid\n  githubRepoId   Int       @unique\n  name           String\n  fullName       String // e.g., \"owner/repo\"\n  webhookId      Int?\n  isActive       Boolean   @default(true)\n  createdAt      DateTime  @default(now())\n  updatedAt      DateTime  @updatedAt\n  deletedAt      DateTime?\n\n  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  scans        Scan[]\n\n  @@index([organizationId])\n  @@map(\"repositories\")\n}\n\nmodel Scan {\n  id           String     @id @default(uuid()) @db.Uuid\n  repositoryId String     @db.Uuid\n  prNumber     Int\n  commitSha    String\n  status       ScanStatus @default(PENDING)\n  triggeredBy  String // GitHub username of the PR author\n  errorMessage String?\n  createdAt    DateTime   @default(now())\n  updatedAt    DateTime   @updatedAt\n\n  repository Repository @relation(fields: [repositoryId], references: [id], onDelete: Cascade)\n  findings   Finding[]\n\n  @@index([repositoryId, status])\n  @@index([createdAt])\n  @@map(\"scans\")\n}\n\nmodel Finding {\n  id                String          @id @default(uuid()) @db.Uuid\n  scanId            String          @db.Uuid\n  filePath          String\n  lineNumber        Int\n  severity          FindingSeverity\n  vulnerabilityType String // e.g., \"SQL_INJECTION\", \"HARDCODED_SECRET\"\n  aiExplanation     String          @db.Text\n  suggestedFix      String          @db.Text\n  githubCommentId   Int?\n  status            FindingStatus   @default(OPEN)\n  createdAt         DateTime        @default(now())\n  updatedAt         DateTime        @updatedAt\n\n  scan Scan @relation(fields: [scanId], references: [id], onDelete: Cascade)\n\n  @@index([scanId])\n  @@index([severity])\n  @@map(\"findings\")\n}\n",
